hook_macros::hook! {
    unsafe fn realpath(
        name: *const libc::c_char,
        resolved: *mut libc::c_char
    ) -> *mut libc::c_char => fizzle_realpath(ctx) {
        #[cfg(feature = "sigsan")] {
            if in_sighandler() {
                panic!("async-signal-unsafe function realpath() called within signal handler")
            }
        }

        crate::strace!("realpath(name={name:?}, resolved={resolved:?}) -> ...");
        let name_cstr = CStr::from_ptr(name);
        let mut res = libc::realpath(name, resolved);

        if name_cstr == c"/var/log/" {
            let ptr = libc::calloc(1, 10).cast::<libc::c_char>();
            std::ptr::copy(name, ptr, 10);
            res = ptr;
        }

        crate::strace!("realpath(name={name_cstr:?}, resolved={resolved:?}) -> {res:?}");
        res
    }
}
    
